namespace UniversityCourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Code { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

namespace UniversityCourseCatalog.Models;

public class Course
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Code { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Credits { get; set; }
    public string Schedule { get; set; } = string.Empty;
    public string InstructorName { get; set; } = string.Empty;
    public string InstructorBio { get; set; } = string.Empty;
    public int DepartmentId { get; set; }
    public string DepartmentName { get; set; } = string.Empty;
    public bool IsFeatured { get; set; }
}

using System.ComponentModel.DataAnnotations;

namespace UniversityCourseCatalog.Models;

public class EnrollmentRequest
{
    [Required(ErrorMessage = "Name is required.")]
    public string StudentName { get; set; } = string.Empty;

    [Required(ErrorMessage = "Student ID is required.")]
    public string StudentId { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please select a course.")]
    [Range(1, int.MaxValue, ErrorMessage = "Please select a course.")]
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Course> _courses;
    private readonly List<EnrollmentRequest> _enrollments = new();

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Name = "Computer Science", Code = "CS", Description = "Study of computation, algorithms, and software systems." },
            new() { Id = 2, Name = "Mathematics", Code = "MATH", Description = "Study of numbers, structures, and patterns." },
            new() { Id = 3, Name = "Physics", Code = "PHYS", Description = "Study of matter, energy, and the fundamental forces of nature." }
        };

        _courses = new List<Course>
        {
            new() { Id = 1, Title = "Introduction to Programming", Code = "CS101", Description = "Learn the fundamentals of programming using C#. Topics include variables, control flow, functions, and object-oriented design.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00-9:50 AM", InstructorName = "Dr. Alice Johnson", InstructorBio = "Dr. Johnson has 15 years of experience teaching introductory programming courses.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true },
            new() { Id = 2, Title = "Data Structures and Algorithms", Code = "CS201", Description = "Study of fundamental data structures including arrays, linked lists, trees, and graphs, along with algorithm analysis.", Credits = 4, Schedule = "Tue/Thu 10:30-11:45 AM", InstructorName = "Dr. Bob Smith", InstructorBio = "Dr. Smith is a published researcher in algorithm optimization.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true },
            new() { Id = 3, Title = "Operating Systems", Code = "CS301", Description = "Concepts of operating system design including process management, memory management, and file systems.", Credits = 3, Schedule = "Mon/Wed 2:00-3:15 PM", InstructorName = "Dr. Carol Williams", InstructorBio = "Dr. Williams worked at a major OS vendor before joining academia.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = false },
            new() { Id = 4, Title = "Calculus I", Code = "MATH101", Description = "Introduction to differential and integral calculus of single-variable functions.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00-10:50 AM", InstructorName = "Dr. David Lee", InstructorBio = "Dr. Lee specializes in mathematical analysis and has authored three textbooks.", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = true },
            new() { Id = 5, Title = "Linear Algebra", Code = "MATH201", Description = "Study of vector spaces, matrices, linear transformations, and eigenvalues.", Credits = 3, Schedule = "Tue/Thu 1:00-2:15 PM", InstructorName = "Dr. Emily Chen", InstructorBio = "Dr. Chen's research focuses on applied linear algebra and numerical methods.", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = false },
            new() { Id = 6, Title = "Differential Equations", Code = "MATH301", Description = "Methods for solving ordinary differential equations with applications in science and engineering.", Credits = 3, Schedule = "Mon/Wed/Fri 11:00-11:50 AM", InstructorName = "Dr. David Lee", InstructorBio = "Dr. Lee specializes in mathematical analysis and has authored three textbooks.", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = false },
            new() { Id = 7, Title = "General Physics I", Code = "PHYS101", Description = "Introduction to mechanics, thermodynamics, and waves.", Credits = 4, Schedule = "Tue/Thu 9:00-10:15 AM", InstructorName = "Dr. Frank Martinez", InstructorBio = "Dr. Martinez is an experimental physicist with expertise in mechanics.", DepartmentId = 3, DepartmentName = "Physics", IsFeatured = true },
            new() { Id = 8, Title = "Electromagnetism", Code = "PHYS201", Description = "Study of electric and magnetic fields, Maxwell's equations, and electromagnetic waves.", Credits = 4, Schedule = "Mon/Wed 3:30-4:45 PM", InstructorName = "Dr. Grace Kim", InstructorBio = "Dr. Kim conducts research in electromagnetic theory and photonics.", DepartmentId = 3, DepartmentName = "Physics", IsFeatured = false },
            new() { Id = 9, Title = "Quantum Mechanics", Code = "PHYS301", Description = "Introduction to quantum theory, wave functions, and the Schrödinger equation.", Credits = 3, Schedule = "Tue/Thu 2:30-3:45 PM", InstructorName = "Dr. Grace Kim", InstructorBio = "Dr. Kim conducts research in electromagnetic theory and photonics.", DepartmentId = 3, DepartmentName = "Physics", IsFeatured = false },
            new() { Id = 10, Title = "Software Engineering", Code = "CS401", Description = "Principles of software development including requirements, design patterns, testing, and project management.", Credits = 3, Schedule = "Tue/Thu 4:00-5:15 PM", InstructorName = "Dr. Alice Johnson", InstructorBio = "Dr. Johnson has 15 years of experience teaching introductory programming courses.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = false }
        };
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses(string? searchTerm, int? departmentId)
    {
        var query = _courses.AsEnumerable();

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            query = query.Where(c =>
                c.Title.Contains(searchTerm, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(searchTerm, StringComparison.OrdinalIgnoreCase));
        }

        if (departmentId.HasValue && departmentId.Value > 0)
        {
            query = query.Where(c => c.DepartmentId == departmentId.Value);
        }

        return query.ToList();
    }

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public void SubmitEnrollmentRequest(EnrollmentRequest request)
    {
        _enrollments.Add(request);
    }
}

