@page "/courses"
@using UniversityCourseCatalog.Services
@inject CatalogService CatalogService

<PageTitle>Courses - University Course Catalog</PageTitle>

<h1>Courses</h1>

<form method="get" action="/courses" class="row g-3 mb-4">
    <div class="col-md-5">
        <input type="text" name="Search" value="@Search" class="form-control" placeholder="Search by title or code..." />
    </div>
    <div class="col-md-4">
        <select name="DepartmentId" class="form-select">
            <option value="">All Departments</option>
            @foreach (var dept in CatalogService.GetDepartments())
            {
                <option value="@dept.Id" selected="@(DepartmentId == dept.Id)">@dept.Name</option>
            }
        </select>
    </div>
    <div class="col-md-3">
        <button type="submit" class="btn btn-primary">Search</button>
    </div>
</form>

@{
    var courses = CatalogService.GetCourses(Search, DepartmentId);
}

@if (courses.Count == 0)
{
    <p>No courses found.</p>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Code</th>
                <th>Title</th>
                <th>Department</th>
                <th>Credits</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var course in courses)
            {
                <tr>
                    <td>@course.Code</td>
                    <td>@course.Title</td>
                    <td>@course.DepartmentName</td>
                    <td>@course.Credits</td>
                    <td><a href="/courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a></td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [SupplyParameterFromQuery]
    public string? Search { get; set; }

    [SupplyParameterFromQuery]
    public int? DepartmentId { get; set; }
}

@page "/courses/{Id:int}"
@using UniversityCourseCatalog.Services
@inject CatalogService CatalogService

<PageTitle>Course Detail - University Course Catalog</PageTitle>

@{
    var course = CatalogService.GetCourse(Id);
}

@if (course is null)
{
    <h1>Course Not Found</h1>
    <p>The requested course could not be found.</p>
}
else
{
    <h1>@course.Title</h1>
    <span class="badge bg-secondary mb-3">@course.Code</span>

    <div class="row mt-3">
        <div class="col-md-8">
            <h4>Description</h4>
            <p>@course.Description</p>

            <h4>Details</h4>
            <ul class="list-unstyled">
                <li><strong>Credits:</strong> @course.Credits</li>
                <li><strong>Schedule:</strong> @course.Schedule</li>
                <li><strong>Department:</strong> @course.DepartmentName</li>
            </ul>
        </div>
        <div class="col-md-4">
            <div class="card">
                <div class="card-body">
                    <h5 class="card-title">Instructor</h5>
                    <p class="card-text"><strong>@course.InstructorName</strong></p>
                    <p class="card-text">@course.InstructorBio</p>
                </div>
            </div>
        </div>
    </div>

    <div class="mt-4">
        <a href="/enroll?CourseId=@course.Id" class="btn btn-success">Enroll in This Course</a>
        <a href="/courses" class="btn btn-outline-secondary ms-2">Back to Course List</a>
    </div>
}

@code {
    [Parameter]
    public int Id { get; set; }
}

@page "/enroll"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService CatalogService

<PageTitle>Enroll - University Course Catalog</PageTitle>

<h1>Course Enrollment</h1>

@if (_submitted)
{
    <div class="alert alert-success">
        <h4>Enrollment Request Submitted!</h4>
        <p>Thank you, <strong>@Input.StudentName</strong>. Your enrollment request for the selected course has been received.</p>
        <a href="/courses" class="btn btn-primary mt-2">Browse More Courses</a>
    </div>
}
else
{
    <EditForm Model="Input" FormName="enrollment" OnValidSubmit="HandleSubmit" method="post">
        <AntiforgeryToken />
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="studentName" class="form-label">Student Name</label>
            <InputText id="studentName" @bind-Value="Input.StudentName" class="form-control" />
            <ValidationMessage For="() => Input.StudentName" />
        </div>

        <div class="mb-3">
            <label for="studentId" class="form-label">Student ID</label>
            <InputText id="studentId" @bind-Value="Input.StudentId" class="form-control" />
            <ValidationMessage For="() => Input.StudentId" />
        </div>

        <div class="mb-3">
            <label for="courseId" class="form-label">Course</label>
            <InputSelect id="courseId" @bind-Value="Input.CourseId" class="form-select">
                <option value="0">-- Select a Course --</option>
                @foreach (var course in CatalogService.GetCourses(null, null))
                {
                    <option value="@course.Id">@course.Code - @course.Title</option>
                }
            </InputSelect>
            <ValidationMessage For="() => Input.CourseId" />
        </div>

        <button type="submit" class="btn btn-primary">Submit Enrollment</button>
    </EditForm>
}

@code {
    [SupplyParameterFromForm]
    private EnrollmentRequest Input { get; set; } = new();

    [SupplyParameterFromQuery]
    public int? CourseId { get; set; }

    private bool _submitted;

    protected override void OnInitialized()
    {
        if (CourseId.HasValue && CourseId.Value > 0 && Input.CourseId == 0)
        {
            Input.CourseId = CourseId.Value;
        }
    }

    private void HandleSubmit()
    {
        CatalogService.SubmitEnrollmentRequest(Input);
        _submitted = true;
    }
}

